-/// Truncate a string and add "..." if needed.
-fn truncate(s: &str, max_len: usize) -> String {
-    if s.len() <= max_len {
-        s.to_string()
-    } else if max_len <= 3 {
-        s[..max_len].to_string()
-    } else {
-        format!("{}...", &s[..max_len - 3])
-    }
-}
